const express = require('express');
const twilio = require('twilio');
const cookieSession = require('cookie-session');

const app = express();
app.use(cookieSession({keys: ['your_secret_key']}));

let sessions = {}; // In memory storage for user sessions

// Twilio client configuration
const twilioClient = twilio(accountSid, authToken);

function sendOTP(phoneNumber) {
  const code = Math.floor(100000 + Math.random() * 900000);
  sessions[phoneNumber] = code;

  twilioClient.messages
    .create({
      body: `Your OTP is ${code}`,
      from: 'twilio_number', // Your Twilio phone number
      to: phoneNumber,
    })
    .then((message) => console.log(message.sid));
}

app.get('/send-otp', (req, res) => {
  const phoneNumber = req.query.phone_number;
  if (!phoneNumber) return res.status(400).json({ error: 'Missing phone number' });

  sendOTP(phoneNumber);
  res.json({ success: true });
});

app.post('/verify-otp', (req, res) => {
  const phoneNumber = req.query.phone_number;
  const code = parseInt(req.query.code);

  if (!phoneNumber || !code) return res.status(400).json({ error: 'Missing phone number or OTP' });

  const storedCode = sessions[phoneNumber];
  delete sessions[phoneNumber];

  if (storedCode === code) {
    res.json({ success: true });
  } else {
    res.status(401).json({ error: 'Invalid OTP' });
  }
});

app.listen(3000, () => console.log('Server started on port 3000'));